INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (31587,'liv2','김민지','','1월 5일 모세방 소식입니다.','오늘 *현이는 조잘조잘 언어수업을 받았습니다.&nbsp;
<div>일주일만에 만난 선생님이 반가웠는 지, "선생님~ 보고싶었어요~"하며 애교를 부리는 모습이 사랑스럽기만 합니다 ^^*&nbsp;</div>
