INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (30923,'liv2','김지은','','9월 11일 바울방 소식입니다','<div>오늘은 추석명절 연휴입니다.</div>
<div>바울방 막내는 오전 캔두도서관에서 놀이활동을 하고 왔습니다.&nbsp;</div>
<div>누나, 형을 만나서 신나게 놀고, 어제 선물로 받은 장난감으로 놀이홛동도 했습니다.</div>
<div>만화영화도 보고, 형들과 노는 것을 좋아하는 막내입니다.</div>
<div>간식도 먹고, 맛있는 스팸참치계란마요 덮밥을 만들어 먹고&nbsp;<span style="font-size: 9pt">오늘도 풍성하게 보냈습니다.</span></div>
<div>건강하게 성장하도록 지도하겠습니다!^^</div>          </td>
        </tr>',306,1662822000,'', '', '', '', '', '');
