INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (30030,'liv2','이소영','','4월30일 솔로몬방 소식입니다.','<p>토요일이라 주말이어서 아동 느지막히 일어나 평소와 같이 즐겁고 건강하게 생활하였습니다.</p>
<p>형들 옆에서 함께 tv도 보고 애교도 부리며 놀았지요.</p>
<p><br /></p>
<p>오늘 주호는 오전에는 행복운동장에서 형님들이 밀어주고 이끌어주는 자전거를 타고 놀이했습니다.</p>
<p>상어가족 노래는 필수지요~!</p>
<p>점심에 스파게티도 잘 먹으며 기분좋게 지냈지요.</p>
<p>졸렸는지 낮잠시간엔 금새 잠들어 푹 자고 일어났답니다.</p>
<p>태블릿에서도 아기상어, 자신이 보고싶은걸 하나 둘 누르며 취향껏 가지고 놀았습니다~!</p>          </td>
        </tr>',359,1651244400,'', '', '', '', '', '');
