INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (29912,'liv2','이소영','','4월 12일 솔로몬방 소식입니다.','<p>완연한 봄날씨입니다.</p>
<p>바람이 살랑살랑 불어 아동의 뺨을 간지럽히고 꽃은 봉우리를 활짝 틔우려 하고 있어요.</p>
<p>아동과 함께 화단의 꽃을 보기도 하고 아동은 손가락으로 가리키며 \'꼬~\'라고도 말하네요.</p>
<p>점점 더 많은 단어와 세상,환경등을 알아가고 있습니다.</p>
<p>식사도 잘 하고 신발도 척 척 신으며 가야할곳이 어딘지 알면서도 장난끼가 넘쳐서 다른 곳으로 가보자고 손을 잡아 이끄네요.</p>
<p>점심시간 후에는 자전거나 퀵보드 타기도 하며 식후 가볍게 몸을 움직입니다.</p>
<p>건강하게 보육하겠습니다.</p>
<p><br /></p>          </td>
        </tr>',297,1649689200,'', '', '', '', '', '');
