INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (28421,'liv2','안유나','','10월 8일 모세방 소식입니다.','- 오늘의 놀이 및 활동 사항 -
<div><br /></div>
<div>&nbsp; 오전에는 막내들끼리 2층 놀이방에 올라가 재미있는 신체놀이를 하였습니다.</div>
<div>방방 점프하기도 하였고 서로 시소를 태워주며 꺄르르 웃기도 하였습니다.</div>
<div>막내는 아직 시소가 낯선지 형들이 다 내린 후 조심스럽게 올라가 봅니다:-)</div>
<div>오후에는 비가 잠깐 그쳐 운동장놀이를 하였습니다.</div>
<div>동생들은 킥보드도 타고 달리기도 하였고</div>
<div>언니들은 이번에 선물받은 워치를 차고 배드민턴을 쳐보았습니다.</div>
<div>배드민턴을 칠 때마다 횟수가 올라가 몇개 쳤는지 큰 소리로 알려주며 신나하였습니다.</div>          </td>
        </tr>',277,1633618800,'', '', '', '', '', '');
