INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (28282,'liv2','김채윤','','9월 19일 솔로몬방 소식입니다.','<p><br /></p>
<p>행복운동장에서 꽃을 보고 도토리가 매일 같이 떨어져서 아이들과 줍는 재미가 좋습니다.</p>
<p>아이들도 도토리를 두손에 쥐고 가득 줍습니다.</p>
<p>각자 자전거를 탈때도 있지만 한명이 타면 친구가 옆에서 밀어주는 일이 잦습니다.</p>
<p>그 친구가 웃는 모습이 좋아서 서로 웃고자 배려하는 모습들을 아이들을 통해 봅니다.</p>
<p>주말오전부터 아이들은 웃음이 가득했습니다.</p>
<p>오후에는 요즘 극장에 다니기 힘들지만 이전에&nbsp;했던 번개맨 공연 영상을 보며 즐거운 시간 보냈습니다. </p>          </td>
        </tr>',284,1631977200,'', '', '', '', '', '');
