INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (27843,'liv2','안유나','','7월 6일 솔로몬방 소식입니다.','- 오늘의 놀이 및 활동 사항 -
<div><br /></div>
<div>&nbsp; 오늘은 아이들과 남산 산책을 다녀왔습니다.</div>
<div>무더운 날씨에도 불구하고 아이들의 발걸음은 너무나도 가볍습니다.</div>
<div>둘레길을 걸으며 꽃구경, 나비구경을 하며 한껏 신이난 아이들-!</div>
<div>둘레길 속 작은 폭포를 바라보며 함박웃음을 짓습니다.</div>
<div>오후에 남동생들은 2층 놀이방에 올라가</div>
<div>방방도 타고 미끄럼틀도 타며 즐거운 신체놀이를 하였습니다.</div>
<div>누나들은 직선, 네모 등 연필로 그림을 그리며 미술놀이를 하였습니다.</div>
<div>또 색종이로 비행기를 접어 날려보며 즐거운 시간을 보냈습니다:-)</div>          </td>
        </tr>',264,1625497200,'', '', '', '', '', '');
