INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (25179,'liv2','안유나','','10월 3일 솔로몬B방 소식입니다.','- 오늘의 놀이 및 활동 사항 -
<div><br /></div>
<div>&nbsp; 오늘 오전에는 모래놀이 장난감을 챙겨 운동장에서 놀이하였습니다.</div>
<div><br /></div>
<div>비가 와서 그런지 땅이 축축해져있어 모래놀이하기 딱 좋은(?) 환경이었습니다.</div>
<div><br /></div>
<div>오빠가 모양틀에 축축한 흙을 넣어 엠버 모양을 만드니 셋째도 따라 만들어 보았습니다.</div>
<div><br /></div>
<div>모래놀이를 하는 도중 개미 한마리가 오자 “무서워요”라고 이야기 하면서도</div>
<div><br /></div>
<div>구경하기 바쁜 아이들입니다&gt;&lt;</div>
<div><br /></div>
<div>아슬아슬하게 개미를 밟지 않고 지나가는 아이들 덕에 개미를 화단으로 무사히 보내주었답니다^^!!</div>
<div><br /></div>
<div>오후에는 나뭇잎을 이용해 프로타주를 해보았습니다.</div>
<div><br /></div>
<div>나뭇잎이 붙어있는 종이를 주니 처음에는 동그라미를 그려보다가&nbsp;</div>
<div><span style="font-size: 9pt"><br /></span></div>
<div><span style="font-size: 9pt">교사가 시범을 보이니 따라 색칠하기도 하고, 동생들은 교사와 함께 색칠해보기도 하였습니다.</span></div>
<div><br /></div>
<div>나뭇잎 잎맥이 예쁘게 표현되는 프로타주,&nbsp;</div>
<div><span style="font-size: 9pt"><br /></span></div>
<div><span style="font-size: 9pt">아이들과 함께 나뭇잎을 관찰하고 새칠해보는 시간이었습니다.</span></div>
<div><span style="font-size: 9pt"><br /></span></div>
<div>아이들이 자연의 아름다움을 느낄 수 있은 시간이었길 바랍니다;)</div>          </td>
        </tr>',260,1601737200,'6257FBBB-C74B-412E-92E9-D7353F858D17.jpeg', '', '', '6257FBBB-C74B-412E-92E9-D7353F858D17.jpeg', '', '');
