INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (23035,'liv2','한자혜','','1월 23일 영아방 소식입니다.','<p>- 오늘의 영아방 놀이 및 활동 사항 - </p>
<p><br />오늘은 정유리 학습 봉사 프로그램으로 여러가지 활동을 하였습니다. </p>
<p>조작 활동으로 구슬꾀기와 퍼즐 맞추기를 하였고,</p>
<p>반복 활동으로 무지개 낙하산을 이용하여 만두 만들어보고</p>
<p>뚜껑으로 터널 통과하는 놀이를 하였습니다. </p>
<p>아이들은 반복 활동으로 활동의 이해도가 높아져서 지시사항을 잘 따르는 모습입니다.</p>
<p>또한 설날을 맞이하여 절하는 방법과 </p>
<p>초콜릿이 담긴 봉투를 받는 활동으로 예절 교육을 해주셨습니다. </p>
<p>우리 어린 친구들은 봉투 받기 급급한 모습이 귀엽습니다.</p>          </td>
        </tr>',252,1579705200,'', '', '', '', '', '');
