INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (20891,'liv2','서보현','qkgkaks1@hanmail.net','4월11일 솔로몬B방입니다','<p>금일은&nbsp; 봉사자선생님들이 오셔서 아가들 미용을 해주셨습니다</p>
<p>다들 귀티나고 잘생겼지만 ^^* 머리를 말끔히 다듬으니 흡족하기만 합니다!</p>
<p>오후에는 운동장에서 자전거 타기를 하며 놀았습니다</p>
<p>아가들이 미세먼지를 체크하고 교사가 괜찮은것 같다고 말하자 그럼 운동장으로 나가자고 합니다.</p>
<p>4살 *지는 킥보드를 탔는데 두어번 넘어져 교사가 네발자전거로 바꿔타는건 어떻겠냐 물어도 대수롭지 않은듯 </p>
<p>계속 킥보드를 타겠다고 하고 네발자전거를 타는 아가들도 뒤에서 빠르게 밀라고만 하니 바람을 가르는 쾌감이 뭔지 아는것만 같습니다;;;</p>
<p><br /></p>
<p><br /></p>
<p><br /></p>          </td>
        </tr>',225,1554994800,'', '', '', '', '', '');
