INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (18200,'liv2','이소영','applehyoji@naver.com','2월 19일 아가방 소식입니다.','<p class="0" style="background: #ffffff; line-height: 120%; mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span lang="EN-US" style="background: #ffffff; letter-spacing: 0pt; font-family: 굴림체; mso-fareast-font-family: 굴림체; mso-ascii-font-family: 굴림체; mso-font-width: 100%; mso-text-raise: 0pt">- 2</span><span style="background: #ffffff; font-family: 굴림체; mso-fareast-font-family: 굴림체">월 </span><span lang="EN-US" style="background: #ffffff; letter-spacing: 0pt; font-family: 굴림체; mso-fareast-font-family: 굴림체; mso-ascii-font-family: 굴림체; mso-font-width: 100%; mso-text-raise: 0pt">19</span><span style="background: #ffffff; font-family: 굴림체; mso-fareast-font-family: 굴림체">일 영아방 봉사자 방문 현황 </span><span lang="EN-US" style="background: #ffffff; letter-spacing: 0pt; font-family: 굴림체; mso-fareast-font-family: 굴림체; mso-ascii-font-family: 굴림체; mso-font-width: 100%; mso-text-raise: 0pt">-</span></p>
<p class="0" style="background: #ffffff; text-align: left; mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span lang="EN-US" style="background: #ffffff; letter-spacing: -0.8pt; font-family: 굴림체; mso-fareast-font-family: 굴림체; mso-ascii-font-family: 굴림체; mso-font-width: 100%; mso-text-raise: 0pt"><span lang="EN-US" style="background: #ffffff; letter-spacing: -0.8pt; font-family: 굴림체; mso-fareast-font-family: 굴림체; mso-ascii-font-family: 굴림체; mso-font-width: 100%; mso-text-raise: 0pt"><span lang="EN-US" style="background: #ffffff; letter-spacing: -0.8pt; font-family: 굴림체; mso-fareast-font-family: 굴림체; mso-ascii-font-family: 굴림체; mso-font-width: 100%; mso-text-raise: 0pt"><span lang="EN-US" style="background: #ffffff; letter-spacing: -0.8pt; font-family: 굴림체; mso-fareast-font-family: 굴림체; mso-ascii-font-family: 굴림체; mso-font-width: 100%; mso-text-raise: 0pt">서양원 님 10:00 ~ 13:15</span></span></span></span></p>
<p class="0" style="background: #ffffff; text-align: left; mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span lang="EN-US" style="background: #ffffff; letter-spacing: -0.8pt; font-family: 굴림체; mso-fareast-font-family: 굴림체; mso-ascii-font-family: 굴림체; mso-font-width: 100%; mso-text-raise: 0pt"><span lang="EN-US" style="background: #ffffff; letter-spacing: -0.8pt; font-family: 굴림체; mso-fareast-font-family: 굴림체; mso-ascii-font-family: 굴림체; mso-font-width: 100%; mso-text-raise: 0pt"><span lang="EN-US" style="background: #ffffff; letter-spacing: -0.8pt; font-family: 굴림체; mso-fareast-font-family: 굴림체; mso-ascii-font-family: 굴림체; mso-font-width: 100%; mso-text-raise: 0pt"><span lang="EN-US" style="background: #ffffff; letter-spacing: -0.8pt; font-family: 굴림체; mso-fareast-font-family: 굴림체; mso-ascii-font-family: 굴림체; mso-font-width: 100%; mso-text-raise: 0pt"><span lang="EN-US" style="background: #ffffff; letter-spacing: -0.8pt; font-family: 굴림체; mso-fareast-font-family: 굴림체; mso-ascii-font-family: 굴림체; mso-font-width: 100%; mso-text-raise: 0pt"><span lang="EN-US" style="background: #ffffff; letter-spacing: -0.8pt; font-family: 굴림체; mso-fareast-font-family: 굴림체; mso-ascii-font-family: 굴림체; mso-font-width: 100%; mso-text-raise: 0pt"><span lang="EN-US" style="background: #ffffff; letter-spacing: -0.8pt; font-family: 굴림체; mso-fareast-font-family: 굴림체; mso-ascii-font-family: 굴림체; mso-font-width: 100%; mso-text-raise: 0pt"><span lang="EN-US" style="background: #ffffff; letter-spacing: -0.8pt; font-family: 굴림체; mso-fareast-font-family: 굴림체; mso-ascii-font-family: 굴림체; mso-font-width: 100%; mso-text-raise: 0pt">주현랑 님</span></span></span></span>&nbsp;10:00 ~ 13:15&nbsp; <o:p></o:p></span></span></span></span></p>
<p class="0" style="background: #ffffff; line-height: 120%; mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span style="background: #ffffff; font-family: 굴림체; mso-fareast-font-family: 굴림체">오늘도 영아방에서 함께 하시느라 수고 많으셨습니다</span><span lang="EN-US" style="background: #ffffff; letter-spacing: 0pt; font-family: 굴림체; mso-fareast-font-family: 굴림체; mso-ascii-font-family: 굴림체; mso-font-width: 100%; mso-text-raise: 0pt">!</span></p>
<p class="0" style="background: #ffffff; line-height: 120%; mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><span lang="EN-US" style="background: #ffffff; letter-spacing: 0pt; font-family: 굴림체; mso-fareast-font-family: 굴림체; mso-ascii-font-family: 굴림체; mso-font-width: 100%; mso-text-raise: 0pt"><span style="background: #ffffff; font-family: 굴림체; mso-fareast-font-family: 굴림체">영아방 아이들을 향한 따뜻한 마음과 사랑 항상 감사드립니다</span><span lang="EN-US" style="background: #ffffff; letter-spacing: 0pt; font-family: 굴림체; mso-fareast-font-family: 굴림체; mso-ascii-font-family: 굴림체; mso-font-width: 100%; mso-text-raise: 0pt">.^^</span></span></p>
<p class="0" style="background: #ffffff; line-height: 120%; mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"></p>
<p class="0" style="background: #ffffff; line-height: 120%; mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><br /></p>
<p class="0" style="background: #ffffff; line-height: 120%; mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt"><br /></p><span lang="EN-US" style="background: #ffffff; letter-spacing: 0pt; font-family: 굴림체; mso-fareast-font-family: 굴림체; mso-ascii-font-family: 굴림체; mso-font-width: 100%; mso-text-raise: 0pt"><span lang="EN-US" style="background: #ffffff; letter-spacing: 0pt; font-family: 굴림체; mso-fareast-font-family: 굴림체; mso-ascii-font-family: 굴림체; mso-font-width: 100%; mso-text-raise: 0pt">오늘은 한 주의 시작이자 코앤코 활동을 하는 날입니다.</span></span>
<p></p>
<p class="0" style="background: #ffffff; line-height: 120%; mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt">형아들의 덩치에 밀려 소극적으로 활동 했지만 오늘은 지난주 보다 더 컸는지 매트 위에서 방방 뛰기도 하고</p>
<p></p>
<p class="0" style="background: #ffffff; line-height: 120%; mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt">형들과 어울려 노는 모습을 보여주는 등 적극적으로 활동하였습니다.</p>
<p class="0" style="background: #ffffff; line-height: 120%; mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt">아가방, 원 전체의 제일 막내인 아동이 점점 다리 힘이 생기는지 3단 쿠션계단을 스스로 기어 올라가기도 하고</p>
<p class="0" style="background: #ffffff; line-height: 120%; mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt">펜스를 잡고 서는 모습이 보였습니다. 아직은 기어다니지만 기어다니고, 서고, 걸어다니는 모습이 머지 않은 것 같아요.</p>
<p class="0" style="background: #ffffff; line-height: 120%; mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt">우수인 오늘, 날씨가 따뜻하고 좋아 내복도 이전에 입었던 것 보다 조금 얇은 내복으로 바꿔 입었답니다.</p>
<p class="0" style="background: #ffffff; line-height: 120%; mso-pagination: none; mso-padding-alt: 0pt 0pt 0pt 0pt">추운 겨울이 지나고 꽃봉오리가 톡-하고 열리듯 우리 아동들 발걸음 가는 길 마다 꽃봉오리가 열렸으면 좋겠습니다.</p>          </td>
        </tr>',299,1519052400,'', '', '', '', '', '');
