INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (11691,'liv2','강유아','','12월 22일 아가방 소식입니다.','<div>- 12월 22일 아가방 자원봉사자 방문 현황 -</div>
<div> </div>
<div>  </div>
<div>10시 ~ 13시 30분까지 서양원님</div>
<div>11시 ~ 13시까지 오연선님</div>
<div>16시 ~ 19시까지 박계영님</div>
<div>15시 ~ 17시가지 김슬기님</div>
<div> </div>
<div> </div>
<div>오늘도 아가방에서 함께하시느라 수고 많으셨습니다!</div>
<div>아가방 아이들을 향한 따뜻한 마음과 사랑 항상 감사드립니다.^^</div>
<div> </div>
<div> </div>
<div> </div>
<div> </div>
<div> </div>
<div> </div>
<div>- 오늘의 아가방 놀이 및 활동 사항 -</div>
<div>&nbsp;</div>
<div>&nbsp;</div>
<div>오늘은 오감발달 텀블키즈 시간을 보내었습니다.</div>
<div>오늘의 주제는 겨울놀이로 아이들이 곧 있을 성탄절을 맞이해</div>
<div>산타망토를 두루고 멋진 포즈를 취해보았습니다.</div>
<div>또한 모형눈을 가지고 눈 놀이를 해 보았는데 스트로품 느낌이 신기했는지</div>
<div>관찰을 오랫동안 하다가 눈의결정 스트로품에는 구멍이 있는 것을 보고</div>
<div>손가락에 하나씩 껴보기도 하고, 촉감을 느껴보는 시간도 가져보았습니다.</div>
<div>&nbsp;</div>
<div>그리고 진짜 눈덩이를 가지고 와 실제 촉감을 느껴보고 차갑고</div>
<div>단단함, 그리고 녹는 것을 알아보며 즐거운 시간을 보낼 수 있었습니다.</div>
<div>&nbsp;</div>
<div>&nbsp;</div>
