INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (8631,'liv2','지은하','badrithya@naver.com','11월21일 아가방 소식입니다.','<p>- 11월 21일 봉사자 현황 -</p>
<p>09:00-13:00 홍수진님, 정은혜님, 강수진님</p>
<p>13:00-16:00&nbsp;이경주님</p>
<p>16:00-19:00&nbsp;정민경님</p>
<p>&nbsp;</p>
<p>- 오늘도 아이들과의 즐거운 시간을 함께 해주셔서 감가합니다.♡-</p>
<p>&nbsp;</p>
<p>- 아가방 놀이 및 활동 -</p>
<p>오늘은 운동을 하는 시간을 가졌습니다.</p>
<p>승호가 아주 잘따라하지요..</p>
<p>지도교사와 함께 끝까지 동작을 따라하는 승호의 모습이</p>
<p>매우 귀엽습니다.</p>
<p>승호는 다른 아이들에 비해 세심한면이 많이 있어요..</p>
<p>진욱이는 같이 하다가도 활동적인것이 더 좋은듯 구르기를</p>
<p>끊임없이 하여 웃음을 주었습니다.</p>
<p>모든 좋아하는 것이 다르지만 그 속에서 융화가 잘되는 우리</p>
<p>아가방 아이들 홧팅!!!!</p>          </td>
        </tr>',460,1384959600,'BBB.jpg', '', '', 'BBB.jpg', '', '');
