INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (8801,'liv2','지은하','badrithya@naver.com','6월4일 아가방 소식입니다.','<p>- 6월 4일 봉사자 현황 -</p>
<p>&nbsp;</p>
<p>09:00 - 13:00 유주연님, 윤여경님, 김태경님</p>
<p>16:00 - 19:00 신수빈님, 김지연님</p>
<p>&nbsp;</p>
<p>- 오늘도 아이들과의 시간을 보내 주셔서 감사합니다.-</p>
<p>&nbsp;</p>
<p>&nbsp;</p>
<p>- 아가방 놀이 및 활동 사항 -</p>
<p>&nbsp;</p>
<p>오늘은 아이들이 꽃잎 관찰하기를 하엿습니다.</p>
<p>꽃잎에 촉감을 느껴보고 냄새도 맡아보며 스스로의 호기심을 </p>
<p>즐겼습니다.</p>
<p>무엇을 하든 집중하는 우리 아이들이 대견합니다.</p>
<p>어떤 환경이든 잘 적응해주는 씩씩한 우리 아이들에게 고맙다고 </p>
<p>이야기 하고 싶습니다.</p>
<p>내일 또 신나게 놀아보자.</p>
<p>&nbsp;</p>          </td>
        </tr>',654,1370271600,'B.jpg', '', '', 'B.jpg', '', '');
