INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (8884,'liv2','지은하','badrithya@naver.com','3월15일 아가방 소식입니다.','<p>-3월 15일 자원봉사 방문 현황-</p>
<p>&nbsp;</p>
<p>♥09:00 - 13:00 김혜정님</p>
<p>♥10:00 - 13:00 김경희님, 류수연님, 이효진님, 최자희님</p>
<p>♥13:00 - 16:00 김다솜님, 김영미님, 신희선님(19:00), 황솔이님, 최아림님</p>
<p>♥16:00 - 19:00 이윤제님, 김지연님</p>
<p>♥17:00 - 20:00 강수진님</p>
<p>&nbsp;</p>
<p>권다혜실습선생님, 지은영실습선생님, 박해옥실습선생님</p>
<p>&nbsp;</p>
<p>- 모두들 감사합니다♡ -</p>
<p>&nbsp;</p>
<p>-오늘 아가방 놀이및 활동사항-</p>
<p>&nbsp;</p>
<p>오늘은 아이들이 운동장 나들이를 하였습니다.</p>
<p>나가기전부터 들떠서 소리를 지르고 자신이 좋아하는 옷과 신발을 아주 신중히</p>
<p>선택하는 진지함도 보였습니다.</p>
<p>너무도 각기 다른 개성으로 신나게 뛰여노는 모습을 보는 것만으로도 기분이 </p>
<p>매우 흐뭇했습니다.</p>
<p>너무도 건강하게 자란 모습에 다시 감사함을 느껴봅니다.</p>
<p>도와주신 모든 분들 감사합니다.</p>
<p>&nbsp;</p>
<p>*현이와 *빈이가 예방접종을 하였습니다.</p>
<p>&nbsp;*현이는 와서는 주사가 아팠고 그래서 울었다면서 자신이 겪은 일을 모두 말하였습니다.</p>
<p>&nbsp;매우 예쁜 아이입니다.</p>
<p>&nbsp;</p>          </td>
        </tr>',774,1363273200,'A.jpg', '', '', 'A.jpg', '', '');
