INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (8915,'liv2','지은하','badrithya@naver.com','2월24일 아가방 소식입니다.','<p>-2월24일 아가방 봉사자 현황-</p>
<p>&nbsp;</p>
<p>09:00 - 13:00&nbsp; 권수인님</p>
<p>10:00 - 13:00&nbsp; 이보람님, 안애랑님,정예슬님</p>
<p>13:00 - 15:00&nbsp;(16:00) 양소정님, 박윤지님, 오준택님</p>
<p>14:00 - 16:00&nbsp; 김정은님</p>
<p>16:00 - 19:00&nbsp; 김수진님, 김진아님</p>
<p>17:00 - 20:00&nbsp; 강수진님</p>
<p>&nbsp;</p>
<p>♥일요일인데도 오셔셔 아이들과 함께하는 모습이 아름답습니다.♥</p>
<p>&nbsp;</p>
<p>&nbsp;</p>
<p>- 오늘 아가방 놀이및 활동 사항-</p>
<p>&nbsp;</p>
<p>오늘 우리 11명 왕자님, 공주님들은&nbsp;많은 봉사자분들의 </p>
<p>사랑속에 즐거운 하루를 보냈습니다.</p>
<p>*호가 다리에 힘이 많이 생겨서 스스로 일어나서 한손만</p>
<p>잡아도 설 수 있고요 </p>
<p>*빈이는 그 작은 몸으로 혼자서 잠깐이지만 설수 있고,</p>
<p>*현이의 애교섞인 목소리에 사람들을 녹였습니다.</p>
<p>모두들 주말 마무리 잘하시고 너무나 감사하단 얘기 하고 싶고요,</p>
<p>저희들은 그 사랑에 힘으로 성장하는 모습 보여드릴께요..♡</p>          </td>
        </tr>',1050,1361631600,'', '', '', '', '', '');
