INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (8918,'liv2','최은경','eun4554@hanmail.net','2월 22일 아가방 소식입니다.','<p>&nbsp; - 아가방 봉사자 -</p>
<p>&nbsp; * 11시30분 - 13시 : 김혜정님</p>
<p>&nbsp; * 13시 - 16시 : 김영미님</p>
<p>&nbsp; * 15시 - 17시&nbsp;: 삼성카드님(남여 2명)</p>
<p>&nbsp; * 16시 - 19시 :황솔이님</p>
<p>&nbsp; * 18시 - 20시 :원새림님</p>
<p>&nbsp; .....모두 여섯분이 수고 해 주셨습니다.</p>
<p>&nbsp; .....감사 드립니다.</p>
<p></p>
<p>&nbsp;</p>
<p></p>
<p>&nbsp; - 아가방&nbsp;이모저모 -</p>
<p>&nbsp; * 이*형 : *호가 종이에 그리는 모습을 궁금하다는 듯이 바라보았다.</p>
<p>&nbsp; * 박*수 : 목욕&nbsp;하는 동안&nbsp;교사와 눈을 떼지 않고 계속 미소 짓는 &nbsp;환한 얼굴이다.</p>
<p>&nbsp; * 박*호 : 현관문에 붙은 고정 장식을 너무나 먹고 싶어했다.</p>
<p>&nbsp; *&nbsp;박*리 :&nbsp;오빠들의 간식을 자기도 빨리 달라고 얼굴을 땅에 코박고 울었다.</p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 육중한 몸으로 *수를 덥쳐서 *수를 곤혹스럽게 했다.</p>
<p>&nbsp;&nbsp;* 연*빈 : 오빠들, 봉사자들과 잘 놀다가도 교사를 발견하면 쾌속으로 질주해 오는데 </p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 아는척을 않는다고 얼굴을 온통 찌그러트리며 서럽게울었다.</p>
<p>&nbsp; *&nbsp;배*욱 : 삼성카드의 남자 봉사자와 함께한 시간을 가장 즐거워했다.</p>
<p>&nbsp;&nbsp;* 박*호 : 밥먹는 모습이 오늘따라 특히 복스럽고 예쁘게 느껴졌다.</p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;그림에 열중하는 모습이 가장 멋있는 *호의 모습이었다.</p>
<p>&nbsp;&nbsp;* 김*현 : 봉사자를 따라 화장실을 가려고 매고 있던 가방을 교사에게 맡기며 " 갖고있어"</p>
<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 라고 말했다.&nbsp;말문이 터져나오고 있다.</p>          </td>
        </tr>',1062,1361458800,'', '', '', '', '', '');
